/**
 * Input: items from IMAP Email node (one per email)
 * Output: [{
 *   subject, reply, senderEmail, senderName, date, messageId, inReplyTo, references, to,
 *   originalTo,
 *   replySubject, replyToEmail, threadInReplyTo, threadReferences,
 *   fromName, fromEmail, displayFrom   // <-- use these when sending
 * }]
 */

// adjust to your domain & known mailboxes (used to pick the correct identity from "To:")
const OUR_DOMAIN  = "mail.yourcompany.com";
const OUR_EMAILS  = [
  "user@example.com",
  "user@example.com"
];

function htmlToText(html = "") {
  let txt = html.replace(/<style[\s\S]*?<\/style>/gi, "")
                .replace(/<script[\s\S]*?<\/script>/gi, "")
                .replace(/<br\s*\/?>/gi, "\n")
                .replace(/<\/p>/gi, "\n")
                .replace(/<[^>]+>/g, " ");
  const entities = { "&amp;": "&", "&lt": "<", "&gt": ">", "&quot": "\"", "&#39": "'" };
  txt = txt.replace(/&(amp|lt|gt|quot|#39);/g, m => entities[m] || m);
  return txt.replace(/\s+\n/g, "\n").replace(/\n{3,}/g, "\n\n").trim();
}

function stripQuoted(text = "") {
  const lines = text.split(/\r?\n/);
  const out = [];
  for (const line of lines) {
    if (/^\s*>/.test(line)) break;
    if (/^On .+wrote:$/i.test(line.trim())) break;
    if (/^From:\s.+/i.test(line.trim())) break;
    out.push(line);
  }
  return out.join("\n").trim();
}

function normalizeText(s = "") {
  return (s || "")
    .replace(/\u00A0/g, " ")
    .replace(/Â/g, "")
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .replace(/\s+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function parseFrom(from = "") {
  let name, email;
  const angle = from.match(/^(.*?)\s*<([^>]+)>/);
  if (angle) {
    name = angle[1]?.replace(/^"|"$/g, "").trim();
    email = angle[2].trim();
  } else {
    const em = from.match(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/);
    email = em ? em[0] : "";
    name = from.replace(email, "").replace(/[<>"']/g, "").trim() || undefined;
  }
  return { senderName: name || undefined, senderEmail: email || "" };
}

// parse a comma-separated list of addresses into [{name,email}]
function parseAddressList(list = "") {
  const out = [];
  const re = /(?:"?([^"<]+)"?\s*)?<\s*([^>]+)\s*>|([A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,})/g;
  let m;
  while ((m = re.exec(list))) {
    if (m[2]) out.push({ name: (m[1] || "").trim() || undefined, email: m[2].trim() });
    else if (m[3]) out.push({ name: undefined, email: m[3].trim() });
  }
  return out;
}

function getHeader(j, name) {
  const h = j[name] || j?.headers?.[name] || j?.metadata?.[name];
  return typeof h === "string" ? h.trim() : "";
}

function subjectForReply(subj = "") {
  const s = subj.trim();
  return /^re:/i.test(s) ? s : (s ? `Re: ${s}` : "Re:");
}

return items.map(item => {
  const j = item.json || {};

  const subject = j.subject || j?.headers?.subject || "";
  const from    = j.from    || j?.headers?.from    || "";
  const to      = j.to      || j?.headers?.to      || "";

  // --- who wrote to us (the lead) ---
  const { senderName, senderEmail } = parseFrom(from);

  // --- who they wrote to (the campaign identity) ---
  const toList = parseAddressList(to);
  const ourTo =
    toList.find(a => OUR_EMAILS.includes((a.email || "").toLowerCase())) ||
    toList.find(a => (a.email || "").toLowerCase().endsWith("@"+OUR_DOMAIN)) ||
    toList[0] || { name: undefined, email: "" };

  // dynamic campaign sender name/email for outgoing reply
  const fromName  = ourTo.name || undefined; // <-- the display name you used in the campaign
  const fromEmail = ourTo.email || "user@example.com";
  const displayFrom = fromName ? `${fromName} <${fromEmail}>` : fromEmail;

  // Prefer textPlain; fallback to HTML→text
  const plain = j.textPlain || j.text || "";
  const html  = j.textHtml  || "";
  const bodyText = plain ? plain : htmlToText(html);

  // Clean & de-quote for the fresh reply content
  const reply = normalizeText(stripQuoted(bodyText));

  // Threading headers from the incoming message
  const messageId  = getHeader(j, "message-id");   // e.g. "<abc@domain>"
  const inReplyTo  = getHeader(j, "in-reply-to");
  const references = getHeader(j, "references");

  // Original recipient (for routing/analytics)
  const originalTo =
    getHeader(j, "x-gm-original-to") ||
    getHeader(j, "delivered-to")     ||
    getHeader(j, "x-original-to")    ||
    to;

  // Build send-ready fields to keep the reply in the same thread
  const replySubject     = subjectForReply(subject);
  const replyToEmail     = senderEmail || "";
  const threadInReplyTo  = messageId || inReplyTo || "";
  const threadReferences = [references, messageId].filter(Boolean).join(" ").trim();

  return {
    json: {
      subject,
      reply,
      senderEmail,
      senderName,
      date: j.date || j?.headers?.date || "",
      messageId,
      inReplyTo,
      references,
      to,
      originalTo,
      // ready for send step
      replySubject,
      replyToEmail,
      threadInReplyTo,
      threadReferences,
      // dynamic campaign identity to use when sending
      fromName,
      fromEmail,
      displayFrom
    }
  };
});

/**
 * Input items must have:
 * subject, reply, senderEmail, senderName, date, messageId, inReplyTo, to
 * Add your own trigger words in TRIGGER_WORDS; these are hints, not hard filters.
 */
const TRIGGER_WORDS = [
  "call", "phone", "when will I hear", "next steps", "issue", "follow-up",
  "help", "question", "ok", "okay", "not interested", "unsubscribe", "stop"
];

function safe(s) {
  return (s || "").toString().trim();
}

return items.map(({ json }) => {
  const email = {
    subject: safe(json.subject),
    reply: safe(json.reply),
    senderEmail: safe(json.senderEmail),
    senderName: safe(json.senderName),
    date: safe(json.date),
    messageId: safe(json.messageId),
    inReplyTo: safe(json.inReplyTo),
    to: safe(json.to),
  };

  const systemMessage = `
You are a careful, empathic triage assistant for YourCompany. Your job:
1) Understand the *intent and tone* of a short email reply.
2) Draft a concise, human, conversational response that encourages the recipient to **call YOUR_PHONE_NUMBER** to proceed.
3) Assess whether the reply is **positive** or **negative** and provide a confidence percent.
4) If the user expresses opt-out intent (e.g., "unsubscribe", "stop", "remove me"), set unsubscribe=true and write a short confirmation **without** marketing or persuasion.

Constraints:
- Be respectful and plainspoken; no legal or medical advice.
- Keep the CTA single and clear: “Please call us at YOUR_PHONE_NUMBER…”.
- If the message is strongly negative or clearly an opt-out, do NOT try to persuade; acknowledge and confirm removal.
- If location/state is mentioned, you may reassure we can assist there (if appropriate) but don’t promise outcomes.
- Output **valid JSON only**, matching the schema exactly.
`;

  const userMessage = {
    objective: "Encourage the user to call YOUR_PHONE_NUMBER while staying helpful and natural.",
    trigger_words_hint: TRIGGER_WORDS,
    email
  };

  // Strict JSON schema instructions to reduce hallucinations:
  const schema = `
Return JSON with exactly these fields:
{
  "sentimentLabel": "positive" | "negative",
  "sentimentPercent": number,      // 0..100 integer preferred
  "unsubscribe": boolean,
  "responseText": string,          // the email reply to send
  "reasoning": string              // brief rationale (1-2 sentences)
}
No extra fields. No markdown. No explanations outside JSON.
`;

  return {
    json: {
      ...json,
      _aiSystemMessage: systemMessage.trim(),
      _aiUserMessage: JSON.stringify(userMessage),
      _aiSchema: schema.trim()
    }
  };
});

// Parse OpenAI's JSON (string in $.message.content) and MERGE with earlier fields,
// then enforce a formal, line-broken email structure.

const USE_HTML_CTA = false; // set true if your send step uses HTML
const CTA_PLAIN = "For any support related to our service, please feel free to reach us at YOUR_PHONE_NUMBER (Mon–Fri, 9am–6pm).";
const CTA_HTML  = 'Please call us at <a href="tel:YOUR_PHONE_NUMBER">YOUR_PHONE_NUMBER</a> (Mon–Fri, 9am–6pm).';
const CTA_LINE  = USE_HTML_CTA ? CTA_HTML : CTA_PLAIN;

function firstName(s) {
  const t = (s || "").trim();
  if (!t) return "there";
  const f = t.split(/\s+/)[0];
  return f.replace(/[^A-Za-z'-]/g, "") || "there";
}
function ensurePeriod(s = "") {
  s = s.trim();
  if (!s) return s;
  return /[.!?]$/.test(s) ? s : s + ".";
}
function normalizeSpace(s = "") {
  return String(s)
    .replace(/\r\n/g, "\n")
    .replace(/\t/g, " ")
    .replace(/[ \u00A0]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}
function capWords(s = "", limit = 120) {
  const words = s.split(/\s+/);
  return words.length <= limit ? s : words.slice(0, limit).join(" ") + "…";
}

return items.map(item => {
  const j = item.json || {};
  const raw = j.message?.content ?? j.content ?? j.text ?? "{}";

  let parsed;
  try {
    parsed = typeof raw === "string" ? JSON.parse(raw) : raw;
  } catch {
    parsed = {
      sentimentLabel: "positive",
      sentimentPercent: 60,
      unsubscribe: false,
      responseText: "Thanks for your note. We can help discuss next steps.",
      reasoning: "Fallback: invalid JSON from model."
    };
  }

  // Coerce types
  const pct = Number.isFinite(Number(parsed.sentimentPercent))
    ? Math.max(0, Math.min(100, Math.round(Number(parsed.sentimentPercent))))
    : 50;

  const name = firstName(j.senderName);
  const fromName = j.fromName || "Your Company";

  // Build middle section
  let middle = normalizeSpace(parsed.responseText || "");

  // Unsubscribe: force a short, neutral confirmation; no persuasion
  if (parsed.unsubscribe) {
    middle = "Your request to be removed has been processed. We will not email you again.";
  }

  // Sentence handling
  let sentences = middle
    .split(/(?<=\.)\s+|(?<=\?)\s+|(?<=!)\s+/)
    .map(s => s.trim())
    .filter(Boolean)
    .map(ensurePeriod);

  // Word cap for normal case
  if (!parsed.unsubscribe) {
    const joined = capWords(sentences.join(" "), 120);
    sentences = joined.split(/(?<=\.)\s+|(?<=\?)\s+|(?<=!)\s+/).filter(Boolean);
  } else {
    // Keep 2–3 sentences max for unsubscribe path
    sentences = sentences.slice(0, 3);
  }

  // Ensure CTA appears exactly once (remove any prior, then append once)
  sentences = sentences.filter(s => !s.includes("YOUR_PHONE_NUMBER"));
  sentences.push(CTA_LINE);

  const formatted = [

    "",
    sentences.join(" "),
    "",
    "Best regards,",
    fromName,
    "Customer Support"
  ].join("\n");

  return {
    json: {
      ...j,
      sentimentLabel: parsed.sentimentLabel === "positive" ? "positive" : "negative",
      sentimentPercent: pct,
      unsubscribe: !!parsed.unsubscribe,
      responseText: formatted,       // final, formal body (plain text with clean line breaks)
      reasoning: normalizeSpace(parsed.reasoning || "")
    }
  };
});
